import json
from datetime import datetime

# Complex JSON data
complex_data = {
    "company": "Neopy",
    "established": 2024,
    "employees": [
        {
            "id": 1,
            "name": "Alice",
            "skills": ["Python", "JavaScript", "SQL"],
            "active": True,
            "projects": [
                {"name": "Web Platform", "status": "active"},
                {"name": "API Gateway", "status": "completed"}
            ]
        },
        {
            "id": 2,
            "name": "Bob",
            "skills": ["Python", "Django", "AWS"],
            "active": True,
            "projects": [
                {"name": "Cloud Migration", "status": "active"}
            ]
        }
    ],
    "metadata": {
        "version": "1.0.0",
        "last_updated": datetime.now().isoformat()
    }
}

# Writing JSON to file
with open('company.json', 'w') as file:
    json.dump(complex_data, file, indent=2, sort_keys=True)

# Pretty print JSON string
json_str = json.dumps(complex_data, indent=2, sort_keys=True)
print(json_str[:500])  # First 500 chars

# Reading JSON from file
with open('company.json', 'r') as file:
    loaded_data = json.load(file)
    print(f"Company: {loaded_data['company']}")
    print(f"Employees: {len(loaded_data['employees'])}")

# Querying JSON data
python_developers = [
    emp['name'] for emp in loaded_data['employees'] 
    if 'Python' in emp['skills']
]
print(f"Python developers: {python_developers}")

# JSON validation and error handling
def validate_json(json_data, required_fields):
    """Validate JSON has required fields"""
    for field in required_fields:
        if field not in json_data:
            raise ValueError(f"Missing required field: {field}")
    return True

try:
    with open('company.json', 'r') as file:
        data = json.load(file)
        validate_json(data, ['company', 'employees'])
        print("JSON is valid")
except json.JSONDecodeError as e:
    print(f"Invalid JSON: {e}")
except ValueError as e:
    print(f"Validation error: {e}")

# Custom JSON encoder for datetime
class DateTimeEncoder(json.JSONEncoder):
    def default(self, obj):
        if isinstance(obj, datetime):
            return obj.isoformat()
        return super().default(obj)

# Using custom encoder
now = datetime.now()
data_with_date = {"timestamp": now, "message": "Hello"}
json_string = json.dumps(data_with_date, cls=DateTimeEncoder, indent=2)
print(json_string)

# Custom decoder for datetime
def datetime_decoder(dict_obj):
    for key, value in dict_obj.items():
        if key == 'timestamp' and isinstance(value, str):
            dict_obj[key] = datetime.fromisoformat(value)
    return dict_obj

parsed_data = json.loads(json_string, object_hook=datetime_decoder)
print(f"Parsed datetime: {parsed_data['timestamp']}")

# Merging multiple JSON files
import glob

all_data = []
for filepath in glob.glob('data_*.json'):
    with open(filepath, 'r') as file:
        data = json.load(file)
        all_data.append(data)

with open('merged.json', 'w') as file:
    json.dump(all_data, file, indent=2)

